---@class LFightBuffExpreCtrl
local LFightBuffExpreCtrl = LxClass("LFightBuffExpreCtrl",nil)

local LFightBuffExpress = LXImport("..View.LFightBuffExpress")

function LFightBuffExpreCtrl:LFightBuffExpreCtrl(battleUnit)
    self._battleUnit = battleUnit

    ---@type table<number,LFightBuffExpress>
    self._expressMap = {}

    self._runningList = {}

    self._runningWaitList = {}

    ---@type table<string,table<number,LFightBuffExpress>> 特殊表现记录
    self._specialExpressMap = {}
end



function LFightBuffExpreCtrl:GetBuffExpre(expressId)
    local expreList = self._expressMap[expressId]
    ---@type LFightBuffExpress
    local express =nil
    if not expreList or #expreList==0 then
        express = LFightBuffExpress:New({expressId = expressId,manager = self._battleUnit})
    else
        express = table.remove(expreList)
    end
    express:Preload()

    return express
end


function LFightBuffExpreCtrl:AddRunningExpre(express)
    table.insert(self._runningList,express)
end

function LFightBuffExpreCtrl:OnRun(time)
    local cnt= #self._runningList
    for k = cnt ,1,-1 do
        local expre = self._runningList[k]
        if expre:IsEnd() then
            table.remove(self._runningList,k)
            expre:OnPlayEnd()
            self:Recycle(expre)
        else
            if expre:IsPersistenceWait() then
                table.insert(self._runningWaitList,expre)
                table.remove(self._runningList,k)
            else
                expre:OnRun(time)
            end
        end
    end

    local waitCnt = #self._runningWaitList
    for k = waitCnt,1,-1 do
        local expre = self._runningWaitList[k]
        if expre:IsEnd() then
            table.remove(self._runningWaitList,k)
            expre:OnPlayEnd()
            self:Recycle(expre)
        end
    end
end

function LFightBuffExpreCtrl:IsNoBuff()
    return #self._runningList == 0
end

function LFightBuffExpreCtrl:ClearBuffExpre()
    if self._runningList then
        for k,v in ipairs(self._runningList) do
            v:Destroy()
        end
        self._runningList = {}
    end

    if self._runningWaitList then
        for k,v in ipairs(self._runningWaitList) do
            v:Destroy()
        end
        self._runningWaitList = {}
    end
end

function LFightBuffExpreCtrl:Recycle(expre)
    local expressId = expre:GetExpressId()
    expre:OnRecycle()
    local list = self._expressMap[expressId]
    if not list then
        list = {}
    end

    table.insert(list,expre)
    self._expressMap[expressId] = list
end

function LFightBuffExpreCtrl:Destroy()
    if self._expressMap then
        for k,v in pairs(self._expressMap) do
            for k1 ,v1 in ipairs(v) do
                v1:Destroy()
            end
        end
        self._expressMap = nil
    end

    if self._runningList then
        for k,v in ipairs(self._runningList) do
            v:Destroy()
        end
        self._runningList = nil
    end

    if self._runningWaitList then
        for k,v in ipairs(self._runningWaitList) do
            if v:IsDestroy() then
                v:Destroy()
            end
        end
        self._runningWaitList = nil
    end

    self._specialExpressMap = nil

    table.removeall(self)
end

---@param tarHero LFightObject
---@param expre LFightBuffExpress
function LFightBuffExpreCtrl:SetSpecialExpre(tarHero,buffUniqueId,expre)
    if not tarHero then return end

    local specialExpressMap = self._specialExpressMap
    if not specialExpressMap then
        specialExpressMap = {}
        self._specialExpressMap = specialExpressMap
    end
    local heroId = tarHero:GetId()
    local heroSpecialExpressMap = specialExpressMap[heroId]
    if not heroSpecialExpressMap then
        heroSpecialExpressMap = {}
        specialExpressMap[heroId] = heroSpecialExpressMap
    end
    heroSpecialExpressMap[buffUniqueId] = expre
end

---@param tarHero LFightObject
function LFightBuffExpreCtrl:RecycleSpecialExpre(tarHero,buffUniqueId)
    if not self._specialExpressMap then return end

    local specialExpressMap = self._specialExpressMap
    local heroId = tarHero:GetId()
    local heroSpecialExpressMap = specialExpressMap[heroId]
    if not heroSpecialExpressMap then return end

    ---@type LFightBuffExpress
    local expre = heroSpecialExpressMap[buffUniqueId]
    if not expre or expre:IsDestroy() then return end

    expre:RecycleSpecialExpre()
    heroSpecialExpressMap[buffUniqueId] = nil
end

---@param tarHero LFightObject
function LFightBuffExpreCtrl:SetSpecialExpressVisible(tarHero,bShow)
    if not self._specialExpressMap then return end

    local specialExpressMap = self._specialExpressMap
    local heroId = tarHero:GetId()
    local heroSpecialExpressMap = specialExpressMap[heroId]
    if not heroSpecialExpressMap then return end

    for k,v in pairs(heroSpecialExpressMap) do
        if not v:IsDestroy() then
            v:SetVisible(bShow)
        end
    end
end

return LFightBuffExpreCtrl






